var e=JSON.parse(`[{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"생각보다 저항이 거세군. 침식체가 얼마 남지 않았을 텐데.","JPN":"思ったより抵抗が続くな。残っている侵食体はさほど多くないはずなんだが。","ENG":"The number of C.O.s should be dwindling, but the resistance is stronger than anticipated.","TWN":"沒想到他們比想像中還要頑強抵抗，侵蝕體應該剩不多才對。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님, 제가 길을 알아요. 여기서 조금만 더 가면…….","JPN":"神父様、私、道を知っておりますわ。ここからもうちょっと行くと……","ENG":"Father, I know the way. If we go a little further from here...","TWN":"神父，我知道路，再往裡面走……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니, 클로디아 자네는 신디와 함께 이곳에 남도록.","JPN":"いや。クラウディア、君はシンディと一緒にここに残ってくれたまえ。","ENG":"No, Claudia. You should remain here with Cindy.","TWN":"不，克勞迪婭，你和辛蒂一起留在這裡。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 그렇지만…….","JPN":"はい？　でも……","ENG":"What? B-but...","TWN":"什麼？可是……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"저것들이 이렇게까지 거세게 저항하는 건, 필히 저 심연 속에 무언가가 일어나고 있다는 뜻이다.","JPN":"侵食体がここまで激しく抵抗するのは、きっとあの深淵の中で何かが起きているという証拠だろう。","ENG":"The only reason those things are resisting so fiercely is because something is happening in the abyss over there.","TWN":"他們會如此頑強抵抗，就表示那個深淵裡一定有什麼。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어쩌면 인신공양을 통한 사악한 의식 같은 것일지도 모르겠지.","JPN":"もしかすると人身御供による邪悪な儀式のようなものかもしれない。","ENG":"Perhaps it is another evil ritual involving human sacrifice.","TWN":"或許是想藉由活祭舉行什麼邪惡的儀式。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇다면 자네 말대로 그 아이가 위험할 거다.","JPN":"だとすると、君の言うとおりその子が危ない。","ENG":"If that is true, then that child will be in danger.","TWN":"若真是如此，那你說的那個孩子就會有危險。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 그러니까 더욱 저의 도움이…….","JPN":"はい、ですから私の助けが……","ENG":"Yes, then all the more reason for me to─","TWN":"沒錯，所以更需要我的幫……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"착각하지 마라, 클로디아.","JPN":"勘違いするな、クラウディア。","ENG":"Do not be mistaken, Claudia.","TWN":"克勞迪婭，你是不是哪裡有誤會？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이 상황에서 그런 몸으로 자네가 우릴 어떻게 돕겠다는 건가?","JPN":"この状況で、身体も万全でない君がどうやって助けになるというんだ。","ENG":"How are you supposed to help anyone in that condition?","TWN":"以你現在的身體，在這種情況下要如何幫我們？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님께서는…… 벌써 눈치채고 계셨군요.","JPN":"神父様は……すでに気付いていらしゃったのですね。","ENG":"Father... I see you've already noticed...","TWN":"神父……原來你有發現。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"미안하군. 하지만 이 세상엔 신앙만으로는 해결할 수 없는 문제도 있다.","JPN":"すまない。だが、この世界には信仰だけで解決できない問題もある。","ENG":"My apologies. However, there are some matters in this world that faith alone cannot solve.","TWN":"抱歉，但在這個世界上，有些問題是光靠信仰無法解決的。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런 문제들을 해결하기 위해서는…… 다른 방식이 필요하지.","JPN":"そのような問題を解決するためには……違う方法が必要なのだ。","ENG":"In order to resolve such issues, we will need... unconventional methods.","TWN":"要解決那些問題……就必須換個方法。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신디! 여긴 네게 맡기겠다. 내가 돌아올 때까지 침식체의 발을 묶어 두도록.","JPN":"シンディ！　ここは君に任せる。私が帰って来るまで侵食体を足止めしておきたまえ。","ENG":"Cindy! I place you in charge here. Keep the C.O.s at bay until I return.","TWN":"辛蒂！這裡交給你，在我回來之前，別讓侵蝕體靠近！"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}}]`);export{e as default};